"use client";

import React, { useEffect, useState } from "react";
import Image from "next/image";
import { toast } from "sonner";
import Link from "next/link";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import { useAuth } from "@/lib/auth-context";
import { apiService } from "@/lib/api-service";
import {
  Activity,
  Award,
  Bell,
  CheckCircle,
  DollarSign,
  Gavel,
  Plus,
  TrendingUp,
  UserCheck,
} from "lucide-react";
import { soundService } from "@/lib/sound-service";
import { Listing, Transaction } from "@prisma/client";

export default function DashboardPage() {
  const { user } = useAuth();
  const [listings, setListings] = useState<Listing[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGoogleLogin = () => {
    soundService.playClick();
    window.location.href = "/api/auth/google";
  };

  useEffect(() => {
    async function loadDashboardData() {
      if (!user) return;
      setIsLoading(true);
      try {
        const [allListings, myTxs] = await Promise.all([
          apiService.getListings(),
          apiService.getTransactions(user.id),
        ]);
        setListings(allListings.filter((l: Listing) => l.sellerId === user.id));
        setTransactions(myTxs);
      } catch {
        setError("Не вдалося завантажити дані кабінету");
        toast.error("Не вдалося завантажити дані кабінету");
      } finally {
        setIsLoading(false);
      }
    }
    loadDashboardData();
  }, [user]);

  if (error) {
    return (
      <div className="flex flex-col min-h-screen bg-[#030712] items-center justify-center p-4">
        <div className="glass-panel p-8 rounded-3xl border border-red-500/20 max-w-md text-center space-y-4">
          <p className="text-sm text-red-400">{error}</p>
          <button onClick={() => window.location.reload()} className="rounded-xl bg-violet-600 hover:bg-violet-500 px-6 py-2.5 text-xs font-bold text-white transition-all">
            Перезавантажити
          </button>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="flex flex-col min-h-screen bg-[#030712] text-white">
        <Navbar />
        <main className="flex-grow flex items-center justify-center p-12">
          <div className="text-center space-y-4 max-w-sm glass-panel p-8 rounded-3xl border border-white/5">
            <UserCheck className="h-10 w-10 text-brand-primary mx-auto animate-pulse" />
            <h2 className="text-xl font-bold font-display">Увійдіть в особистий кабінет</h2>
            <p className="text-xs text-slate-400">
              Кабінет показує тільки реальні лоти, домовленості та дані вашого акаунта.
            </p>
            <button
              onClick={handleGoogleLogin}
              onMouseEnter={() => soundService.playHover()}
              className="w-full rounded-2xl bg-brand-primary hover:bg-brand-primary-hover active:bg-brand-primary px-6 py-3.5 text-sm font-bold text-white shadow-[0_0_30px_rgba(16,185,129,0.3)] transition-all hover:shadow-[0_0_40px_rgba(16,185,129,0.5)]"
            >
              Увійти через Google
            </button>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  const directAgreements = transactions.filter(
    (t) => t.sellerId === user.id && t.paymentStatus === "DIRECT_AGREEMENT"
  );
  const totalAgreementAmount = directAgreements.reduce((sum, t) => sum + t.amount, 0);
  const activeListingsCount = listings.filter((l) => l.status === "ACTIVE").length;
  const auctionListingsCount = listings.filter((l) => l.status === "ACTIVE" && l.type !== "BUY_NOW").length;
  const completedListingsCount = listings.filter((l) => l.status === "COMPLETED").length;
  const listingsWithPhotos = listings.filter((l) => Array.isArray(l.images) && l.images.length > 0).length;
  const listingsWithDescriptions = listings.filter((l) => (l.description || "").trim().length >= 80).length;

  const checklist = [
    { label: "Google-акаунт підключено", done: Boolean(user.email), href: null as string | null },
    { label: "Створити перший реальний лот", done: listings.length > 0, href: "/sell" },
    {
      label: "Додати фото до всіх активних лотів",
      done: listings.length > 0 && listingsWithPhotos === listings.length,
      href: "/sell",
    },
    { label: "Отримати першу пряму домовленість", done: directAgreements.length > 0, href: "/messages" },
  ];
  const completedChecklist = checklist.filter((item) => item.done).length;
  const sellerProgress = Math.round((completedChecklist / checklist.length) * 100);
  const sellerStatus = directAgreements.length >= 5
    ? "Досвідчений продавець"
    : directAgreements.length >= 1
      ? "Активний продавець"
      : listings.length >= 1
        ? "Новий продавець"
        : "Профіль без лотів";
  const nextStep = checklist.find((item) => !item.done);

  return (
    <div className="flex flex-col min-h-screen bg-[#030712] bg-grid-pattern relative overflow-hidden">
      <Navbar />

      <div className="absolute top-[10%] left-[5%] w-[450px] h-[450px] bg-brand-primary/5 rounded-full blur-[140px] pointer-events-none animate-ambient-slow" />
      <div className="absolute bottom-[20%] right-[5%] w-[400px] h-[400px] bg-violet-600/5 rounded-full blur-[130px] pointer-events-none animate-ambient-slow" />

      <main className="flex-grow max-w-7xl w-full mx-auto px-4 py-8 sm:px-6 lg:px-8 relative z-10 space-y-8">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h1 className="text-3xl font-black text-white font-display tracking-tight leading-none">
              Кабінет продавця
            </h1>
            <p className="text-xs text-slate-400 mt-1.5">
              Тільки реальні лоти, домовленості та технічний стан інтеграцій. Без фейкових продажів, переглядів і статусів.
            </p>
          </div>
          <Link
            href="/sell"
            onMouseEnter={() => soundService.playHover()}
            onClick={() => soundService.playClick()}
            className="rounded-xl bg-gradient-to-r from-brand-primary to-brand-primary hover:from-brand-primary-hover hover:to-brand-primary text-xs font-bold text-white px-4 py-2.5 transition-all shadow-lg shadow-brand-primary/15 flex items-center gap-1.5 border border-brand-primary/20"
          >
            <Plus className="h-4 w-4" />
            Створити лот
          </Link>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <MetricCard
            label="Режим платформи"
            value="0 UAH"
            note="KRAM не веде баланс і не обробляє платежі"
            icon={<DollarSign className="h-5 w-5 text-brand-primary" />}
          />
          <MetricCard
            label="Сума домовленостей"
            value={`${totalAgreementAmount.toLocaleString()} UAH`}
            note="Це сума прямих домовленостей, не дохід KRAM"
            icon={<TrendingUp className="h-5 w-5 text-violet-400" />}
          />
          <MetricCard
            label="Активні лоти"
            value={`${activeListingsCount} лотів`}
            note={`З них аукціонів: ${auctionListingsCount}`}
            icon={<Gavel className="h-5 w-5 text-amber-400" />}
          />
          <MetricCard
            label="Завершені домовленості"
            value={`${directAgreements.length} угод`}
            note="Фіксуються тільки реальні домовленості"
            icon={<CheckCircle className="h-5 w-5 text-sky-400" />}
          />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-stretch">
          <div className="lg:col-span-2 glass-panel p-6 rounded-3xl border border-white/5 flex flex-col justify-between shadow-2xl relative overflow-hidden">
            <div className="flex justify-between items-start mb-6 gap-4">
              <div>
                <h3 className="text-base font-bold text-white font-display flex items-center gap-2">
                  <Activity className="h-4 w-4 text-brand-primary" />
                  Реальна активність продавця
                </h3>
                <p className="text-[10px] text-slate-400">
                  Показуємо тільки дані з ваших лотів і домовленостей у базі KRAM.
                </p>
              </div>
              <Link href="/sell" className="rounded-xl border border-white/10 px-3 py-2 text-[10px] font-bold text-slate-200 hover:bg-white/5 transition-all">
                Додати лот
              </Link>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
              <RealityCard title="Усі ваші лоти" value={String(listings.length)} note={`Активні: ${activeListingsCount} • Завершені: ${completedListingsCount}`} />
              <RealityCard title="Фото й описи" value={`${listingsWithPhotos}/${listings.length || 0}`} note={`З описом 80+ символів: ${listingsWithDescriptions}`} accent="text-brand-primary" />
              <RealityCard title="Прямі домовленості" value={String(directAgreements.length)} note="KRAM не обробляє оплату" accent="text-violet-400" />
            </div>

            {isLoading ? (
              <div className="mt-6 rounded-2xl border border-white/5 bg-white/[0.03] p-5 text-sm text-slate-400">
                Завантаження реальних даних...
              </div>
            ) : listings.length === 0 ? (
              <div className="mt-6 rounded-2xl border border-brand-primary/15 bg-brand-primary/5 p-5 text-sm text-slate-300 leading-relaxed">
                Статистика порожня, бо у вас ще немає лотів. Це нормальний реальний стан — ми не малюємо фейкові продажі, перегляди або графіки.
              </div>
            ) : (
              <div className="mt-6 rounded-2xl border border-white/5 bg-slate-950/50 p-5 text-xs text-slate-400 leading-relaxed">
                Перегляди не показуються, поки ми не підключили реальний трекінг переглядів. Замість цього показуємо тільки лоти, фото, описи та домовленості.
              </div>
            )}
          </div>

          <div className="glass-panel p-6 rounded-3xl border border-white/5 flex flex-col justify-between shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-24 h-24 bg-brand-primary/5 rounded-full blur-xl pointer-events-none" />
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <Award className="h-5 w-5 text-brand-primary" />
                <h3 className="text-base font-bold text-white font-display">Статус продавця: {sellerStatus}</h3>
              </div>
              <p className="text-[10px] text-slate-400 leading-normal">
                Статус формується автоматично з реальних дій: лоти, фото, описи та прямі домовленості. Ніяких “золотих” бейджів без даних.
              </p>

              <div className="space-y-1.5 pt-2">
                <div className="flex justify-between text-[10px] font-bold">
                  <span className="text-slate-400">Заповнення профілю продавця:</span>
                  <span className="text-brand-primary">{sellerProgress}%</span>
                </div>
                <div className="h-2 w-full bg-slate-950 rounded-full overflow-hidden border border-white/5 p-0.5">
                  <div className="h-full bg-gradient-to-r from-brand-primary to-teal-400 rounded-full transition-all duration-500" style={{ width: `${sellerProgress}%` }} />
                </div>
              </div>

              <div className="space-y-2.5 pt-4">
                {checklist.map((item, index) => (
                  <div key={item.label} className="flex items-center justify-between gap-3 text-[10px]">
                    <span className={item.done ? "text-brand-primary font-semibold" : "text-slate-400"}>
                      {item.done ? "✓" : `${index + 1}.`} {item.label}
                    </span>
                    {item.done ? (
                      <span className="rounded px-1.5 py-0.5 text-[8px] font-bold bg-brand-primary/10 text-brand-primary">Готово</span>
                    ) : item.href ? (
                      <Link href={item.href} className="rounded px-1.5 py-0.5 text-[8px] font-bold bg-brand-primary text-white hover:bg-brand-primary-hover transition-colors">Перейти</Link>
                    ) : (
                      <span className="rounded px-1.5 py-0.5 text-[8px] font-bold bg-white/5 text-slate-500">Очікує</span>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="text-[10px] text-slate-500 border-t border-white/5 pt-4 text-center mt-4">
              {nextStep ? `Наступний крок: ${nextStep.label}` : "Профіль продавця заповнений за доступними реальними критеріями."}
            </div>
          </div>
        </div>

        <section className="grid grid-cols-1 gap-8 items-stretch">
          <div className="glass-panel p-8 rounded-3xl border border-white/5 bg-slate-950/40 flex flex-col md:flex-row items-center justify-between gap-6 shadow-2xl relative overflow-hidden">
            <div className="space-y-3 max-w-2xl text-center md:text-left">
              <div className="flex items-center justify-center md:justify-start gap-3">
                <div className="bg-brand-primary/10 p-2.5 rounded-2xl border border-brand-primary/20">
                  <Bell className="h-6 w-6 text-brand-primary" />
                </div>
                <h3 className="text-2xl font-bold text-white font-display">Сповіщення та інтеграції</h3>
              </div>
              <p className="text-sm text-slate-300 leading-relaxed">
                Telegram-бот, push-сповіщення та мобільні застосунки будуть увімкнені тільки після реального підключення інтеграцій. Зараз панель показує лише дані, які вже є у вашій базі.
              </p>
            </div>
            <div className="rounded-2xl border border-white/10 bg-white/[0.03] px-5 py-4 text-xs text-slate-400 text-center">
              Статус: очікує підключення реальних каналів
            </div>
          </div>
        </section>

        <section className="glass-panel p-8 rounded-3xl border border-white/5 space-y-6">
          <div className="flex justify-between items-center border-b border-white/5 pb-4">
            <div>
              <h3 className="text-lg font-bold text-white font-display">Ваші реальні лоти ({listings.length})</h3>
              <p className="text-xs text-slate-400 mt-1">Тут показуються тільки лоти, створені вашим акаунтом.</p>
            </div>
          </div>

          {listings.length === 0 ? (
            <div className="py-12 text-center text-xs text-slate-500">
              Ви ще не виставили жодного лота. Створіть ваше перше оголошення!
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left text-xs text-slate-400">
                <thead>
                  <tr className="border-b border-white/5 text-slate-500 text-[10px] uppercase font-bold tracking-wider">
                    <th className="py-3">Фото та назва</th>
                    <th className="py-3">Формат</th>
                    <th className="py-3">Поточна ціна</th>
                    <th className="py-3">Статус</th>
                    <th className="py-3 text-right">Керування</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {listings.map((l) => (
                    <tr key={l.id} className="hover:bg-white/[0.01] transition-colors">
                      <td className="py-4">
                        <div className="flex items-center gap-3">
                          <Image src={l.images?.[0] || "/placeholder.png"} width={64} height={40} unoptimized className="h-10 w-16 object-cover rounded-lg border border-white/10" alt="" />
                          <div>
                            <span className="font-bold text-slate-200 block max-w-[200px] truncate">{l.title}</span>
                            <span className="text-[10px] text-slate-500 block">Створено: {new Date(l.createdAt).toLocaleDateString()}</span>
                          </div>
                        </div>
                      </td>
                      <td className="py-4">
                        {l.type === "AUCTION" && <span className="text-violet-400">🔨 Аукціон</span>}
                        {l.type === "BUY_NOW" && <span className="text-brand-primary">⚡ Фіксована ціна</span>}
                        {l.type === "HYBRID" && <span className="text-sky-400">💎 Гібрид</span>}
                      </td>
                      <td className="py-4 font-bold text-white">{l.currentPrice.toLocaleString()} UAH</td>
                      <td className="py-4">
                        {l.status === "ACTIVE" ? (
                          <span className="inline-flex items-center gap-1 text-[10px] text-brand-primary font-semibold bg-brand-primary/10 px-2 py-0.5 rounded-full border border-brand-primary/20">Активний</span>
                        ) : (
                          <span className="inline-flex items-center gap-1 text-[10px] text-slate-500 font-semibold bg-white/5 px-2 py-0.5 rounded-full border border-white/10">Завершено</span>
                        )}
                      </td>
                      <td className="py-4 text-right">
                        <Link
                          href={`/lot/${l.id}`}
                          onMouseEnter={() => soundService.playHover()}
                          onClick={() => soundService.playClick()}
                          className="rounded-lg bg-slate-800 hover:bg-slate-700 text-white px-3 py-1.5 text-[10px] font-bold border border-white/5 transition-all inline-flex items-center gap-1"
                        >
                          Дивитися лот
                        </Link>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </section>
      </main>

      <Footer />
    </div>
  );
}

function MetricCard({ label, value, note, icon }: { label: string; value: string; note: string; icon: React.ReactNode }) {
  return (
    <div className="glass-panel p-6 rounded-3xl border border-white/5 relative overflow-hidden flex flex-col justify-between min-h-[140px]">
      <div className="absolute top-0 right-0 w-20 h-20 bg-brand-primary/5 rounded-full blur-lg pointer-events-none" />
      <div className="flex justify-between items-start">
        <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">{label}</span>
        {icon}
      </div>
      <div className="mt-4">
        <p className="text-2xl font-black text-white font-display">{value}</p>
        <span className="text-[10px] text-slate-500 block mt-1">{note}</span>
      </div>
    </div>
  );
}

function RealityCard({ title, value, note, accent = "text-white" }: { title: string; value: string; note: string; accent?: string }) {
  return (
    <div className="rounded-2xl border border-white/5 bg-white/[0.03] p-5">
      <p className="text-[10px] uppercase tracking-wider text-slate-500 font-bold">{title}</p>
      <p className={`text-3xl font-black font-display mt-2 ${accent}`}>{value}</p>
      <p className="text-[10px] text-slate-500 mt-2">{note}</p>
    </div>
  );
}
